import{_ as l,c as a,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"cc-switch","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/cc-switch-开发工具.md","filePath":"github汇总/开发工具/cc-switch-开发工具.md"}'),t={name:"github汇总/开发工具/cc-switch-开发工具.md"};function h(n,i,c,o,s,d){return e(),a("div",null,i[0]||(i[0]=[r('<h1 id="cc-switch" tabindex="-1">cc-switch <a class="header-anchor" href="#cc-switch" aria-label="Permalink to “cc-switch”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>cc-switch</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>farion1231</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>开发工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>在不同AI编码工具之间切换需要手动编辑配置文件，管理MCP和Skills很麻烦。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>AI编码工具一体化管理器，支持Claude Code、Codex、Gemini CLI、OpenCode和OpenClaw五种工具。提供50多个预设提供商（AWS Bedrock、NVIDIA NIM、社区中转服务等），一键导入。统一管理MCP服务器和Skills，一个面板管理四个应用，双向同步配置。系统托盘快速切换。支持云同步（Dropbox、OneDrive、iCloud、WebDAV）。本地代理支持热切换、自动故障转移、熔断器。使用统计和成本跟踪。Deep Link导入支持。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>支持5种AI编码工具</li><li>50+预设提供商</li><li>统一MCP和Skills管理</li><li>系统托盘快速切换</li><li>云同步支持</li><li>本地代理和故障转移</li><li>使用统计和成本跟踪</li><li>原生桌面应用（Tauri 2）</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/farion1231/cc-switch" target="_blank" rel="noreferrer">https://github.com/farion1231/cc-switch</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用CC Switch管理AI编码工具的用户。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><strong>检查操作系统</strong><ul><li>执行命令：无</li><li>通过标准：Windows 10+、macOS 12+或主流Linux发行版</li></ul></li></ol><h3 id="主路径-windows安装" tabindex="-1">主路径：Windows安装 <a class="header-anchor" href="#主路径-windows安装" aria-label="Permalink to “主路径：Windows安装”">​</a></h3><p><strong>步骤1：下载安装包</strong></p><ul><li>目标：获取安装包</li><li>位置：浏览器</li><li>操作：访问GitHub Releases页面下载MSI安装包或便携版</li><li>成功标志：文件下载完成</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：安装应用</strong></p><ul><li>目标：安装CC Switch</li><li>位置：本地</li><li>操作：运行MSI安装包，按提示完成安装</li><li>成功标志：应用安装成功</li><li>失败处理：检查系统权限</li></ul><p><strong>步骤3：启动应用</strong></p><ul><li>目标：运行CC Switch</li><li>位置：桌面或开始菜单</li><li>操作：打开CC Switch应用</li><li>成功标志：应用窗口打开</li><li>失败处理：检查系统兼容性</li></ul><h3 id="备选路径1-macos安装" tabindex="-1">备选路径1：macOS安装 <a class="header-anchor" href="#备选路径1-macos安装" aria-label="Permalink to “备选路径1：macOS安装”">​</a></h3><p><strong>步骤1：使用Homebrew安装（推荐）</strong></p><ul><li>目标：通过Homebrew安装</li><li>位置：终端</li><li>命令：<code>brew tap farion1231/ccswitch &amp;&amp; brew install --cask cc-switch</code></li><li>成功标志：安装成功提示</li><li>失败处理：检查Homebrew是否正确安装</li></ul><p><strong>步骤2：或手动下载</strong></p><ul><li>目标：下载macOS版本</li><li>位置：浏览器</li><li>操作：访问GitHub Releases下载macOS版本</li><li>成功标志：文件下载完成</li><li>失败处理：检查网络连接</li></ul><h3 id="备选路径2-linux安装" tabindex="-1">备选路径2：Linux安装 <a class="header-anchor" href="#备选路径2-linux安装" aria-label="Permalink to “备选路径2：Linux安装”">​</a></h3><p><strong>步骤1：下载对应格式</strong></p><ul><li>目标：获取Linux安装包</li><li>位置：浏览器</li><li>操作：访问GitHub Releases下载deb、rpm、AppImage或flatpak</li><li>成功标志：文件下载完成</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：安装</strong></p><ul><li>目标：安装应用</li><li>位置：终端</li><li>命令：根据格式使用对应命令安装</li><li>成功标志：安装成功</li><li>失败处理：检查依赖</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>应用正常启动</li><li>可以添加提供商</li><li>可以切换不同的AI工具配置</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>macOS提示&quot;无法验证开发者&quot;</strong></p><ul><li>可能原因：应用未签名</li><li>解决步骤：系统设置 → 隐私与安全 → 仍要打开</li></ul></li><li><p><strong>无法删除当前活跃提供商</strong></p><ul><li>可能原因：系统需要保持一个活跃配置</li><li>解决步骤：先切换到其他提供商再删除</li></ul></li><li><p><strong>配置同步失败</strong></p><ul><li>可能原因：云服务连接问题</li><li>解决步骤：检查云服务账号和网络连接</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/farion1231/cc-switch#documentation" target="_blank" rel="noreferrer">CC Switch User Manual</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',45)]))}const u=l(t,[["render",h]]);export{b as __pageData,u as default};
